),
"AHA.Heart Failure Outpatient Encounter" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation") AS QualifyingEncounter WHERE CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(QualifyingEncounter.resource, 'status') = 'finished' AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-encounter-diagnosis)") AS HeartFailure WHERE intervalOverlaps(CASE WHEN fhirpath_text(HeartFailure.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), fhirpath_text(HeartFailure.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(QualifyingEncounter.resource, 'period')) AND (fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartFailure.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND HeartFailure.patient_id = QualifyingEncounter.patient_id)
),
"AHA.Moderate or Severe LVSD Findings" AS (
(SELECT patient_id, resource FROM "Observation: Ejection Fraction" AS EjectionFraction WHERE quantity_compare(parse_quantity(EjectionFraction.value), parse_quantity('{"value": 40.0, "unit": "%", "system": "http://unitsofmeasure.org"}'), '<=') AND array_contains(['final', 'amended', 'corrected'], EjectionFraction.status)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-encounter-diagnosis)" UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-encounter-diagnosis)") AS LVSDDiagnosis WHERE in_valueset(LVSDDiagnosis.resource, 'severity', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1092'))) AS ModerateOrSevereLVSD WHERE (fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ModerateOrSevereLVSD.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"AHA.Qualifying Outpatient Encounter During Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Patient Provider Interaction") AS ValidEncounter WHERE CAST(intervalStart(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished'
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS (
SELECT * FROM "AHA.Heart Failure Outpatient Encounter" AS HFOutpatientEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Moderate or Severe LVSD Findings") AS LVSDFindings WHERE CAST(intervalStart(COALESCE(CASE WHEN fhirpath_text(LVSDFindings.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), fhirpath_text(LVSDFindings.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVSDFindings.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, CASE WHEN fhirpath_text(LVSDFindings.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVSDFindings.resource, 'effective')), '{') THEN fhirpath_text(LVSDFindings.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(LVSDFindings.resource, 'effective'), fhirpath_text(LVSDFindings.resource, 'effective'), TRUE, TRUE) END)) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(HFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND LVSDFindings.patient_id = HFOutpatientEncounter.patient_id)
),
"AHA.Is Adults With Two Qualifying Outpatient Encounters and One Heart Failure Outpatient Encounter During the Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18 AND EXISTS (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period" AS Encounter1 WHERE Encounter1.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period") AS Encounter2 WHERE NOT CASE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL AND fhirpath_text(Encounter1.resource, 'id') IS NULL THEN TRUE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL OR fhirpath_text(Encounter1.resource, 'id') IS NULL THEN FALSE ELSE fhirpath_text(Encounter2.resource, 'id') = fhirpath_text(Encounter1.resource, 'id') END AND Encounter2.patient_id = Encounter1.patient_id)) AND EXISTS (SELECT 1 FROM "AHA.Heart Failure Outpatient Encounter" AS sub WHERE sub.patient_id = p.patient_id)
),
"AHA.Has Heart Transplant" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Heart Transplant" AS HeartTransplant WHERE HeartTransplant.patient_id = p.patient_id AND fhirpath_text(HeartTransplant.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(intervalStart(CASE WHEN fhirpath_text(HeartTransplant.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartTransplant.resource, 'performed')), '{') THEN fhirpath_text(HeartTransplant.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HeartTransplant.resource, 'performed'), fhirpath_text(HeartTransplant.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplant.patient_id))
),
"AHA.Has Heart Transplant Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-problems-health-concerns)") AS HeartTransplantComplications WHERE HeartTransplantComplications.patient_id = p.patient_id AND (fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartTransplantComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplantComplications.patient_id))
),
"AHA.Has Left Ventricular Assist Device" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Left Ventricular Assist Device Placement" AS LVADOutpatient WHERE LVADOutpatient.patient_id = p.patient_id AND fhirpath_text(LVADOutpatient.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(intervalStart(CASE WHEN fhirpath_text(LVADOutpatient.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVADOutpatient.resource, 'performed')), '{') THEN fhirpath_text(LVADOutpatient.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(LVADOutpatient.resource, 'performed'), fhirpath_text(LVADOutpatient.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADOutpatient.patient_id))
),
"AHA.Has Left Ventricular Assist Device Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-problems-health-concerns)") AS LVADComplications WHERE LVADComplications.patient_id = p.patient_id AND (fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(LVADComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(COALESCE(fhirpath_text(LVADComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(LVADComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), fhirpath_text(LVADComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADComplications.patient_id))
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "AHA.Has Heart Transplant" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Heart Transplant Complications" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Left Ventricular Assist Device" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Left Ventricular Assist Device Complications" AS sub WHERE sub.patient_id = p.patient_id)
),
"Has ACEI or ARB or ARNI Ordered" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "MedicationRequest: ACE Inhibitor or ARB or ARNI" AS ACEIOrARBOrARNIOrdered WHERE ACEIOrARBOrARNIOrdered.patient_id = p.patient_id AND CAST(fhirpath_text(ACEIOrARBOrARNIOrdered.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS DATE) AND CAST(fhirpath_text(ACEIOrARBOrARNIOrdered.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND array_contains(['active', 'completed'], fhirpath_text(ACEIOrARBOrARNIOrdered.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(ACEIOrARBOrARNIOrdered.resource, 'intent')))
),
"Has Allergy or Intolerance to ACEI or ARB or ARNI Ingredient" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "AllergyIntolerance: ACE Inhibitor or ARB or ARNI Ingredient" UNION SELECT patient_id, resource FROM "AllergyIntolerance: Substance with angiotensin-converting enzyme inhibitor mechanism of action (substance)" UNION SELECT patient_id, resource FROM "AllergyIntolerance: Substance with angiotensin II receptor antagonist mechanism of action (substance)" UNION SELECT patient_id, resource FROM "AllergyIntolerance: Substance with neprilysin inhibitor mechanism of action (substance)") AS ACEIOrARBOrARNIAllergyIntolerance WHERE ACEIOrARBOrARNIAllergyIntolerance.patient_id = p.patient_id AND intervalOverlaps(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset'), fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset'), fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(ACEIOrARBOrARNIAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) > COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND fhirpath_bool(ACEIOrARBOrARNIAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()') AND fhirpath_bool(ACEIOrARBOrARNIAllergyIntolerance.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-verification'' and code=''confirmed'').exists()'))
),
"Has Diagnosis of Allergy or Intolerance to ACEI or ARB" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Allergy to ACE Inhibitor or ARB (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Intolerance to ACE Inhibitor or ARB (qicore-condition-problems-health-concerns)") AS ACEIOrARBAllergyOrIntoleranceDiagnosis WHERE ACEIOrARBAllergyOrIntoleranceDiagnosis.patient_id = p.patient_id AND intervalOverlaps(CASE WHEN fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) > COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND (fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ACEIOrARBAllergyOrIntoleranceDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Diagnosis of Pregnancy" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Condition: Pregnancy (qicore-condition-problems-health-concerns)" AS PregnancyDiagnosis WHERE PregnancyDiagnosis.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(intervalStart(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '9 month' <= CAST(intervalStart(CASE WHEN fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PregnancyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PregnancyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS TIMESTAMP) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = PregnancyDiagnosis.patient_id))
),
"Has Diagnosis of Renal Failure Due to ACEI" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Acute renal failure caused by angiotensin-converting-enzyme inhibitor (disorder) (qicore-condition-encounter-diagnosis)" AS RenalFailureDueToACEI WHERE RenalFailureDueToACEI.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(RenalFailureDueToACEI.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), fhirpath_text(RenalFailureDueToACEI.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(RenalFailureDueToACEI.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(RenalFailureDueToACEI.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), fhirpath_text(RenalFailureDueToACEI.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(RenalFailureDueToACEI.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(RenalFailureDueToACEI.resource, 'onsetDateTime'), fhirpath_text(RenalFailureDueToACEI.resource, 'onsetPeriod.start'), fhirpath_text(RenalFailureDueToACEI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS DATE) AND (fhirpath_bool(RenalFailureDueToACEI.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(RenalFailureDueToACEI.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(RenalFailureDueToACEI.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(RenalFailureDueToACEI.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Medical or Patient Reason for Not Ordering ACEI or ARB or ARNI" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "MedicationRequest: ACE Inhibitor or ARB or ARNI (medicationnotrequested)" AS NoACEIOrARBOrARNIOrdered WHERE NoACEIOrARBOrARNIOrdered.patient_id = p.patient_id AND CAST(fhirpath_text(NoACEIOrARBOrARNIOrdered.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS DATE) AND CAST(fhirpath_text(NoACEIOrARBOrARNIOrdered.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND fhirpath_text(NoACEIOrARBOrARNIOrdered.resource, 'status') = 'completed' AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(NoACEIOrARBOrARNIOrdered.resource, 'intent')) AND (in_valueset(NoACEIOrARBOrARNIOrdered.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007') OR in_valueset(NoACEIOrARBOrARNIOrdered.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1008') OR in_valueset(NoACEIOrARBOrARNIOrdered.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1140')))
),
"Denominator Exceptions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Medical or Patient Reason for Not Ordering ACEI or ARB or ARNI" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Allergy or Intolerance to ACEI or ARB or ARNI Ingredient" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Diagnosis of Allergy or Intolerance to ACEI or ARB" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Diagnosis of Pregnancy" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Diagnosis of Renal Failure Due to ACEI" AS sub WHERE sub.patient_id = p.patient_id)
),
"Initial Population" AS (
SELECT * FROM "AHA.Is Adults With Two Qualifying Outpatient Encounters and One Heart Failure Outpatient Encounter During the Measurement Period"
),
"Denominator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Initial Population" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id)
),
"Is Currently Taking ACEI or ARB or ARNI" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "MedicationRequest: ACE Inhibitor or ARB or ARNI" AS ActiveACEIOrARBOrARNI WHERE ActiveACEIOrARBOrARNI.patient_id = p.patient_id AND intervalOverlaps(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveACEIOrARBOrARNI.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(intervalEnd(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveACEIOrARBOrARNI.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1)) AS DATE), CAST('9999-12-31' AS DATE)) > COALESCE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND array_contains(['active', 'completed'], fhirpath_text(ActiveACEIOrARBOrARNI.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(ActiveACEIOrARBOrARNI.resource, 'intent')))
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has ACEI or ARB or ARNI Ordered" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Is Currently Taking ACEI or ARB or ARNI" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Denominator Exceptions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exceptions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Denominator Exceptions" ON p.patient_id = "Denominator Exceptions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
